import { describe, expect, it } from "vitest";
import { buildTemplatePreviewUrl } from "./startTemplatePreview.js";
describe("buildTemplatePreviewUrl", () => {
    it("builds the chromeless preview URL for a simple key", () => {
        expect(buildTemplatePreviewUrl("https://bitfab.ai", "my-fn")).toBe("https://bitfab.ai/plugin/trace-functions/my-fn/template-preview");
    });
    it("preserves the configured host and port", () => {
        expect(buildTemplatePreviewUrl("http://localhost:3001", "my-fn")).toBe("http://localhost:3001/plugin/trace-functions/my-fn/template-preview");
    });
    it("URL-encodes function keys with reserved characters", () => {
        expect(buildTemplatePreviewUrl("https://bitfab.ai", "scope/sub key")).toBe("https://bitfab.ai/plugin/trace-functions/scope%2Fsub%20key/template-preview");
    });
});
